P - Packaging - DM' ds ELSE ( CASE WHEN C_AETC_REAS = '17' THEN '17 - SR/IP - JIT Failure to Ship to SDS' ds ELSE ( CASE WHEN C_AETC_REAS = '18' THEN '18 - SR/IP - Ship Code Non-Conformance' ds ELSE ( CASE WHEN C_AETC_REAS = '19' THEN '19 - SR/IP - Deviation from Routing Instructions' ds ELSE ( CASE WHEN C_AETC_REAS = '20' THEN '20 - SR/IP - Shipped to Wrong Plant' ds ELSE ( CASE WHEN C_AETC_REAS = '21' THEN '21 - SR/IP - Incorrect Part/Quantity - RDR' ds ELSE ( CASE WHEN C_AETC_REAS = '22' THEN '22 - SR/IP - ASN Failure' ds ELSE ( CASE WHEN C_AETC_REAS = '23' THEN '23 - SR/IP - Pre-Production' ds ELSE ( CASE WHEN C_AETC_REAS = '24' THEN '24 - SR/IP - Line Down/Equipment Failure' ds ELSE ( CASE WHEN C_AETC_REAS = '25' THEN '25 - SR/IP - International RDR Pending' ds ELSE ( CASE WHEN C_AETC_REAS = '35' THEN '35 - SR/IP - Container Return' ds ELSE ( CASE WHEN C_AETC_REAS = '36' THEN '36 - SR/IP - Tooling Repair' ds ELSE ( CASE WHEN C_AETC_REAS = '37' THEN '37 - SR/IP - Non-Prod Material' ELSE 'Undefined Reason in Query' END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END ) END as N_AETC_REAS,
